@startuml
skinparam classAttributeIconSize 0

class "Personnage" <<(A,#ADD1B2)>> {
    void combattre()
    void setArme(ComportementArme)
}

interface "ComportementArme" <<I>> {
    +void utiliserArme()
}

abstract class Aventure <<C>> {
    abstract main(String[]) : int*
}


' Classes concrètes héritant de Personnage
class Troll <<C>> 
class Roi <<C>>  
class Reine <<C>>   
class Chevalier <<C>> 

' Implémentations du comportement d'arme
class ComportementPoignard <<C>>{
   -utiliserArme():int;
 }
class ComportementEpee<<C>>{
     -utiliserArme();
 }
class ComportementArc<<C>>{
      -utiliserArme();
 }



Troll --|> Personnage
Roi --> Personnage
Reine -> Personnage
Chevalier ---> Personnage 


note right of Troll #line:Trolls sont des personnages maléfiques\nqui attaquent les autres.\nLeur méthode 'attaquer()' est implémentée\ndans la classe parente abstraite."#end note leftof King:"Les rois dirigent leur peuple avec sagesse et justice.Leurs décisions influencent tout le royaume.""Queen":"La reine soutient son mari dans ses tâches royales.Elle joue un rôle important au sein du gouvernement royal.","Knight":''' Les chevaliers servent fidèlement leurs seigneurs.Ils protègent innocents contre menaces extérieures.'''




@enduml
